def process_frame(self, frame):
    if self._streaming_sum is None:
        self._streaming_sum = frame.clone()
    else:
        self._streaming_sum += frame
    self._frame_count += 1
    profile = (self._streaming_sum / self._frame_count).unsqueeze(-1)
    return self.forward(profile)

class SpectralTrainer:
    def __init__(self, config_path="conf/config.yaml", resume_from=None):
        self.cfg = load_config(config_path)
        seed = self.cfg.get("seed", 42)
        torch.manual_seed(seed)

def load_config(path="conf/config.yaml"):
    with open(path, "r") as f:
        return yaml.safe_load(path)
